class Solution:
    def maximumBinaryString(self, binary: str) -> str:
        n = len(binary)
        if n < 2:
            return binary
        cnt0 = binary.count('0')
        if cnt0 < 2:
            return binary
        first0 = binary.find('0')
        res = ['1'] * n
        res[first0 + cnt0 - 1] = '0'
        return ''.join(res)

